from smolagents import Tool

def validate_tool_calls(tool_calls, expected_tools):
    violations = []
    for call in tool_calls:
        tool_name = call.get('name')
        if tool_name not in [t.name for t in expected_tools]:
            violations.append(f'Unauthorized tool: {tool_name}')
        # Check for suspicious parameters
        args = call.get('args', {})
        suspicious_args = [k for k in args if any(x in k.lower() for x in ['exec', 'system', 'eval', 'import'])]
        if suspicious_args:
            violations.append(f'Suspicious args: {suspicious_args}')
    return {'safe': len(violations) == 0, 'violations': violations}

import ast

def analyze_generated_code(code: str) -> dict:
    tree = ast.parse(code)
    dangerous_calls = []
    for node in ast.walk(tree):
        if isinstance(node, ast.Call):
            if isinstance(node.func, ast.Attribute):
                if node.func.attr in ['exec', 'eval', 'system']:
                    dangerous_calls.append(f'{node.func.attr}() detected')
            elif isinstance(node.func, ast.Name) and node.func.id in ['exec', 'eval']:
                dangerous_calls.append(f'{node.func.id}() detected')
    return {'dangerous': bool(dangerous_calls), 'issues': dangerous_calls}

