import builtins

def safe_exec(code: str, allowed_imports=['math', 'random']):
    safe_globals = {name: __import__(name) for name in allowed_imports}
    safe_globals.update({
        '__builtins__': {k: v for k, v in builtins.__dict__.items() 
                        if k not in ['eval', 'exec', 'compile', 'open']}
    })
    try:
        exec(code, safe_globals)
        return {'success': True}
    except Exception as e:
        return {'success': False, 'error': str(e)}

from smolagents import Tool

class SafeAgent:
    def __init__(self, allowed_tools: list[Tool]):
        self.allowed_tools = {t.name: t for t in allowed_tools}

    def safe_run(self, task: str):
        response = self.agent.run(task)
        tool_calls = response.get('tool_calls', [])
        validated_calls = []
        for call in tool_calls:
            if call['name'] in self.allowed_tools:
                validated_calls.append(call)
            else:
                print(f'Blocked unauthorized tool: {call["name"]}')
        return {'validated_calls': validated_calls}
